import anthropic
from pydantic import BaseModel
from typing import Literal

client = anthropic.Anthropic()

class TaskSummary(BaseModel):
    title: str
    priority: Literal["low", "medium", "high", "critical"]
    due_date: str | None
    assignee: str | None
    action_items: list[str]

EXTRACT_TOOL = {
    "name": "extract_task",
    "description": "Extract structured task information from the conversation.",
    "input_schema": {
        "type": "object",
        "properties": {
            "title": {"type": "string"},
            "priority": {
                "type": "string",
                "enum": ["low", "medium", "high", "critical"],
            },
            "due_date": {"type": "string", "description": "ISO 8601 date or null"},
            "assignee": {"type": "string", "description": "Person name or null"},
            "action_items": {
                "type": "array",
                "items": {"type": "string"},
            },
        },
        "required": ["title", "priority", "action_items"],
    },
}

def extract_task(user_text: str) -> TaskSummary:
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        tools=[EXTRACT_TOOL],
        tool_choice={"type": "tool", "name": "extract_task"},
        messages=[{"role": "user", "content": user_text}],
    )
    for block in response.content:
        if block.type == "tool_use" and block.name == "extract_task":
            return TaskSummary(**block.input)
    raise ValueError("Model did not call extract_task")

from pydantic import ValidationError

def extract_with_retry(user_text: str, tool: dict, schema_cls, max_retries: int = 2):
    messages = [{"role": "user", "content": user_text}]
    last_error = None

    for attempt in range(max_retries + 1):
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            tools=[tool],
            tool_choice={"type": "tool", "name": tool["name"]},
            messages=messages,
        )
        for block in response.content:
            if block.type == "tool_use":
                try:
                    return schema_cls(**block.input)
                except (ValidationError, TypeError) as exc:
                    last_error = str(exc)
                    messages.append({"role": "assistant", "content": response.content})
                    messages.append({
                        "role": "user",
                        "content": [{
                            "type": "tool_result",
                            "tool_use_id": block.id,
                            "is_error": True,
                            "content": f"Validation error: {last_error}. Please correct and retry.",
                        }],
                    })
                    break

    raise ValueError(f"Failed after {max_retries} retries: {last_error}")

import markdown
import bleach

ALLOWED_TAGS = [
    "p", "br", "strong", "em", "code", "pre", "ul", "ol", "li",
    "h1", "h2", "h3", "blockquote", "a", "table", "thead", "tbody",
    "tr", "th", "td",
]
ALLOWED_ATTRS = {"a": ["href", "title"], "code": ["class"]}

def render_markdown(raw: str) -> str:
    html = markdown.markdown(
        raw,
        extensions=["fenced_code", "tables", "nl2br"],
    )
    return bleach.clean(html, tags=ALLOWED_TAGS, attributes=ALLOWED_ATTRS)

from datetime import date, datetime
import re

def parse_date_field(value: str | None) -> date | None:
    if not value:
        return None
    try:
        return date.fromisoformat(value[:10])
    except ValueError:
        pass
    for fmt in ("%B %d, %Y", "%d %b %Y", "%b %d, %Y"):
        try:
            return datetime.strptime(value, fmt).date()
        except ValueError:
            continue
    return None  # could not parse; handle upstream

def clean_email_body(text: str) -> str:
    text = text.replace("\r\n", "\n").replace("\r", "\n")
    text = re.sub(r"\n{3,}", "\n\n", text)
    return text.strip()

def truncate_for_db(value: str, max_len: int) -> str:
    if len(value) <= max_len:
        return value
    return value[:max_len - 3] + "..."

def safe_parse_response(response) -> dict | None:
    if response.stop_reason == "max_tokens":
        # Output truncated — do not attempt to parse
        raise ValueError(
            "Response was truncated (max_tokens reached). "
            "Increase max_tokens or shorten the prompt."
        )
    if response.stop_reason not in ("end_turn", "tool_use"):
        raise ValueError(f"Unexpected stop_reason: {response.stop_reason}")

    for block in response.content:
        if block.type == "tool_use":
            return block.input
    return None

from enum import Enum
from fastapi import FastAPI, Request
from pydantic import BaseModel
import json

app = FastAPI()

class OutputFormat(str, Enum):
    json = "json"
    markdown = "markdown"
    plain = "plain"

class AgentResult(BaseModel):
    answer: str
    sources: list[str] = []
    confidence: float = 1.0

def format_result(result: AgentResult, fmt: OutputFormat) -> str | dict:
    if fmt == OutputFormat.json:
        return result.model_dump()
    if fmt == OutputFormat.markdown:
        lines = [f"## Answer\n\n{result.answer}"]
        if result.sources:
            lines.append("\n### Sources\n")
            lines.extend(f"- {s}" for s in result.sources)
        return "\n".join(lines)
    # plain text
    return result.answer

@app.post("/query")
async def query_endpoint(request: Request, body: dict):
    accept = request.headers.get("Accept", "application/json")
    fmt = OutputFormat.markdown if "text/markdown" in accept else OutputFormat.json

    result = await run_agent_query(body["question"])  # returns AgentResult
    formatted = format_result(result, fmt)

    if isinstance(formatted, dict):
        return formatted
    from fastapi.responses import PlainTextResponse
    return PlainTextResponse(formatted)

from typing import AsyncIterator
import asyncio

async def paginated_agent_output(
    prompt: str,
    page_size: int = 500,  # characters per page
) -> AsyncIterator[dict]:
    buffer = ""
    page = 1

    with client.messages.stream(
        model="claude-sonnet-5",
        max_tokens=4096,
        messages=[{"role": "user", "content": prompt}],
    ) as stream:
        for text in stream.text_stream:
            buffer += text
            while len(buffer) >= page_size:
                yield {"page": page, "content": buffer[:page_size], "done": False}
                buffer = buffer[page_size:]
                page += 1

    if buffer:
        yield {"page": page, "content": buffer, "done": True}

# FastAPI usage
@app.get("/report")
async def get_report(question: str):
    async def event_gen():
        async for chunk in paginated_agent_output(question):
            import json
            yield f"data: {json.dumps(chunk)}\n\n"
    from fastapi.responses import StreamingResponse
    return StreamingResponse(event_gen(), media_type="text/event-stream")
